/// Lookup phi(z) with linear interpolation.
#[inline(always)]
pub fn phi_lut(z: I80F48) -> I80F48 {
    interp(&PHI_LUT, z)
}

/// Lookup Phi(z) with linear interpolation.
#[inline(always)]
pub fn cdf_lut(z: I80F48) -> I80F48 {
    let z_f: f64 = z.to_num();
    if z_f <= LUT_Z_MIN { return I80F48::ZERO; }
    if z_f >= -LUT_Z_MIN { return I80F48::ONE; }
    interp(&CDF_LUT, z)
}

#[inline(always)]
fn interp(table: &[f64; 257], z: I80F48) -> I80F48 {
    let z_f: f64 = z.to_num();
    let idx_f = (z_f - LUT_Z_MIN) * LUT_INV_STEP;
    let idx = idx_f as usize;
    if idx >= LUT_N { return I80F48::from_num(table[LUT_N]); }
    let frac = idx_f - idx as f64;
    let val = table[idx] + frac * (table[idx + 1] - table[idx]);
    I80F48::from_num(val)
}
